package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

public class CSVFormatTest {

    @Test
    public void testWithDelimiter_ValidDelimiter() {
        // Given
        char delimiter = ',';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newFormat = csvFormat.withDelimiter(delimiter);

        // Then
        assertEquals(delimiter, newFormat.getDelimiter());
    }

    @Test
    public void testWithDelimiter_InvalidDelimiter_LineBreak() {
        // Given
        char delimiter = '\n';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When/Then
        assertThrows(IllegalArgumentException.class, () -> csvFormat.withDelimiter(delimiter));
    }

